<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  body {
    font-family: system-ui, -apple-system, sans-serif;
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
    color: #333;
  }
  h1, h2 { color: #222; }
  .form-group { margin-bottom: 12px; }
  .form-group label { display: inline-block; width: 80px; font-weight: 500; }
  input, select { padding: 6px; border: 1px solid #ccc; border-radius: 4px; }
  button { padding: 8px 12px; background: #007bff; color: white; border: none; border-radius: 4px; cursor: pointer; }
  button:hover { background: #0056b3; }
  .error { color: #d00; margin-top: 10px; font-weight: bold; min-height: 1.2em; }
  table { width: 100%; border-collapse: collapse; margin-top: 20px; }
  th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }
  th { background: #f4f4f4; }
  .hidden { display: none; }
  .summary, .filters { margin-top: 20px; padding: 15px; background: #f9f9f9; border: 1px solid #ddd; border-radius: 4px; }
  .summary div { margin-bottom: 8px; }
  .cat-total { font-weight: bold; color: #007bff; }
  .filters label { margin-right: 5px; margin-left: 15px; font-weight: 500; }
  .filters label:first-child { margin-left: 0; }
  .exp-del { background: #dc3545; padding: 4px 8px; font-size: 0.9em; }
  .exp-del:hover { background: #c82333; }
</style>
</head>
<body>

  <h1>Personal Expense Tracker</h1>

  <form id="expense-form">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note</label>
      <input type="text" id="note" placeholder="Optional">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
    <div id="form-error" class="error"></div>
  </form>

  <div class="filters">
    <label for="filter-category">Category</label>
    <select id="filter-category">
      <option value="all">all</option>
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>

    <label for="filter-from">From</label>
    <input type="date" id="filter-from">

    <label for="filter-to">To</label>
    <input type="date" id="filter-to">
  </div>

  <div class="summary">
    <div>Total (visible): $<span id="total">0.00</span></div>
    <div>groceries: <span class="cat-total" data-cat="groceries">0.00</span></div>
    <div>transport: <span class="cat-total" data-cat="transport">0.00</span></div>
    <div>bills: <span class="cat-total" data-cat="bills">0.00</span></div>
    <div>fun: <span class="cat-total" data-cat="fun">0.00</span></div>
  </div>

  <table>
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th>Action</th>
      </tr>
    </thead>
    <tbody id="expense-list">
    </tbody>
  </table>

<script>
  const STORAGE_KEY = 'expenses';
  let expenses = [];
  try {
    expenses = JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
  } catch (e) {
    expenses = [];
  }

  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categoryInput = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');

  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  const expenseList = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const catTotals = document.querySelectorAll('.cat-total');

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  function formatMoney(num) {
    return Number(num).toFixed(2);
  }

  function render() {
    const sorted = [...expenses].sort((a, b) => {
      if (a.date === b.date) {
        return b.id - a.id;
      }
      return a.date < b.date ? 1 : -1;
    });

    const catFilter = filterCategory.value;
    const fromDate = filterFrom.value;
    const toDate = filterTo.value;

    expenseList.innerHTML = '';
    let visibleTotal = 0;
    const visibleCatTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };

    sorted.forEach(exp => {
      let visible = true;
      if (catFilter !== 'all' && exp.category !== catFilter) {
        visible = false;
      }
      if (fromDate && exp.date < fromDate) {
        visible = false;
      }
      if (toDate && exp.date > toDate) {
        visible = false;
      }

      const tr = document.createElement('tr');
      tr.className = 'expense' + (visible ? '' : ' hidden');

      const tdAmount = document.createElement('td');
      tdAmount.textContent = formatMoney(exp.amount);
      const tdCat = document.createElement('td');
      tdCat.textContent = exp.category;
      const tdDate = document.createElement('td');
      tdDate.textContent = exp.date;
      const tdNote = document.createElement('td');
      tdNote.textContent = exp.note || '';
      const tdAction = document.createElement('td');

      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.dataset.id = exp.id;
      tdAction.appendChild(delBtn);

      tr.appendChild(tdAmount);
      tr.appendChild(tdCat);
      tr.appendChild(tdDate);
      tr.appendChild(tdNote);
      tr.appendChild(tdAction);

      expenseList.appendChild(tr);

      if (visible) {
        const amt = parseFloat(exp.amount);
        visibleTotal += amt;
        if (visibleCatTotals.hasOwnProperty(exp.category)) {
          visibleCatTotals[exp.category] += amt;
        } else {
          visibleCatTotals[exp.category] = amt;
        }
      }
    });

    totalEl.textContent = formatMoney(visibleTotal);

    catTotals.forEach(el => {
      const cat = el.getAttribute('data-cat');
      const val = visibleCatTotals[cat] || 0;
      el.textContent = formatMoney(val);
    });
  }

  form.addEventListener('submit', (e) => {
    e.preventDefault();
    formError.textContent = '';

    const amountVal = amountInput.value.trim();
    const amount = parseFloat(amountVal);
    const date = dateInput.value;

    if (amountVal === '' || isNaN(amount) || amount <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }
    if (!date) {
      formError.textContent = 'Please select a date.';
      return;
    }

    const newExpense = {
      id: Date.now(),
      amount: amount,
      category: categoryInput.value,
      date: date,
      note: noteInput.value.trim()
    };

    expenses.push(newExpense);
    save();
    render();

    formError.textContent = '';
    amountInput.value = '';
  });

  expenseList.addEventListener('click', (e) => {
    if (e.target.classList.contains('exp-del')) {
      const id = parseInt(e.target.dataset.id, 10);
      expenses = expenses.filter(exp => exp.id !== id);
      save();
      render();
    }
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  render();
</script>
</body>
</html>
